using System;

public class LCS
{
    public static int Lcs(string x, string y)
    {
        int m = x.Length;
        int n = y.Length;
        int[,] dp = new int[m + 1, n + 1];

        for (int i = 1; i <= m; i++)
        {
            for (int j = 1; j <= n; j++)
            {
                if (x[i - 1] == y[j - 1])
                    dp[i, j] = dp[i - 1, j - 1] + 1;
                else
                    dp[i, j] = Math.Max(dp[i - 1, j], dp[i, j - 1]);
            }
        }

        return dp[m, n];
    }

    static void Main(string[] args)
    {
        Console.WriteLine(Lcs("ABCBDAB", "BDCAB")); // 4
    }
}

